-- Split the legacy "solution" / "info" columns into two semantically distinct
-- guidance tracks coming from the updated manufacturer error-code sheet:
--   * operator_guidance          (what the operator can attempt themselves)
--   * technical_support_guidance (escalation steps for tech personnel)
--
-- Codes are unchanged; only descriptions, causes, and guidance bodies are
-- refreshed against the latest spreadsheet.

ALTER TABLE plc_error_codes RENAME COLUMN solution TO operator_guidance;
ALTER TABLE plc_error_codes RENAME COLUMN info     TO technical_support_guidance;

ON CONFLICT (code) DO UPDATE SET
  severity                   = EXCLUDED.severity,
  description                = EXCLUDED.description,
  cause                      = EXCLUDED.cause,
  operator_guidance          = EXCLUDED.operator_guidance,
  technical_support_guidance = EXCLUDED.technical_support_guidance;
